"use client";

import Image from "next/image";
import Link from "next/link";
import { usePathname, useRouter } from "next/navigation";
import { signOut } from "firebase/auth";
import { Activity, FileText, LayoutDashboard, LogOut, ShieldCheck, UserSearch, Users } from "lucide-react";
import { Button } from "@/components/ui/button";
import { ThemeToggle } from "@/components/theme-toggle";
import { clearAuthSession, getUser } from "@/lib/auth";
import { firebaseAuth } from "@/lib/firebase";
import { publicAssetPath } from "@/lib/paths";
import { cn } from "@/lib/utils";

const nav = [
  { href: "/dashboard", label: "Dashboard", icon: LayoutDashboard },
  { href: "/applicants", label: "Applicant Tracking", icon: UserSearch },
  { href: "/interns", label: "Employment Records", icon: Users },
  { href: "/documents/generate", label: "Documents", icon: FileText },
  { href: "/bgv/access", label: "BGV Access", icon: ShieldCheck },
  { href: "/system/status", label: "System Status", icon: Activity }
];

const advocateNav = [{ href: "/advocate", label: "Advocate Desk", icon: LayoutDashboard }];

export function AppShell({ children }: { children: React.ReactNode }) {
  const pathname = usePathname();
  const router = useRouter();
  const user = getUser();
  const navItems = user?.role === "Advocate" ? advocateNav : nav;

  async function logout() {
    await signOut(firebaseAuth).catch(() => undefined);
    clearAuthSession();
    router.replace("/login");
  }

  return (
    <div className="min-h-screen bg-muted/30">
      <aside className="fixed inset-y-0 left-0 hidden w-64 border-r border-border bg-background lg:block">
        <div className="flex h-20 items-center border-b border-border px-5">
          <Image src={publicAssetPath("/lumentix-logo.png")} alt="Lumentix" width={188} height={71} priority />
        </div>
        <nav className="space-y-1 p-4">
          {navItems.map((item) => {
            const Icon = item.icon;
            const active = pathname === item.href || pathname.startsWith(`${item.href}/`);
            return (
              <Link
                key={item.href}
                href={item.href}
                className={cn(
                  "flex h-10 items-center gap-3 rounded-lg px-3 text-sm font-medium text-muted-foreground transition-colors hover:bg-muted hover:text-foreground",
                  active && "bg-muted text-foreground"
                )}
              >
                <Icon className="h-4 w-4" />
                {item.label}
              </Link>
            );
          })}
        </nav>
      </aside>
      <div className="lg:pl-64">
        <header className="sticky top-0 z-30 flex h-16 items-center justify-between border-b border-border bg-background/95 px-4 backdrop-blur lg:px-8">
          <div>
            <p className="text-xs uppercase text-muted-foreground">LUMENTIX HRFLOW</p>
            <p className="text-sm font-medium">{user?.email ?? "Signed in"}</p>
          </div>
          <div className="flex items-center gap-2">
            <ThemeToggle />
            <Button variant="outline" onClick={logout}>
              <LogOut className="mr-2 h-4 w-4" />
              Logout
            </Button>
          </div>
        </header>
        <nav className="flex gap-2 overflow-x-auto border-b border-border bg-background px-4 py-2 lg:hidden">
          {navItems.map((item) => {
            const Icon = item.icon;
            const active = pathname === item.href || pathname.startsWith(`${item.href}/`);

            return (
              <Link
                key={item.href}
                href={item.href}
                className={cn(
                  "inline-flex h-9 shrink-0 items-center gap-2 rounded-lg px-3 text-xs font-medium text-muted-foreground hover:bg-muted hover:text-foreground",
                  active && "bg-muted text-foreground"
                )}
              >
                <Icon className="h-3.5 w-3.5" />
                {item.label}
              </Link>
            );
          })}
        </nav>
        <main className="p-4 lg:p-8">{children}</main>
      </div>
    </div>
  );
}
